/* TabSwitcher.css - 现代简约风格，包含渐变效果 */

:root {
  --ts-primary-gradient: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  --ts-bg-color: #ffffff;
  --ts-text-color: #333333;
  --ts-text-inactive: #888888;
  --ts-border-radius: 12px;
  --ts-shadow: 0 4px 12px rgba(0, 0, 0, 0.1);
}

.tab-switcher-container {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  background: var(--ts-bg-color);
  border-radius: var(--ts-border-radius);
  box-shadow: var(--ts-shadow);
  overflow: hidden;
  width: 100%;
  max-width: 800px;
  margin: 20px auto;
}

/* 标签栏区域 */
.tab-list {
  display: flex;
  border-bottom: 1px solid #eee;
  background: #fafafa;
  padding: 10px 10px 0 10px;
}

.tab-item {
  display: flex;
  align-items: center;
  padding: 12px 20px;
  cursor: pointer;
  color: var(--ts-text-inactive);
  font-weight: 500;
  transition: all 0.3s ease;
  border-bottom: 2px solid transparent;
  margin-bottom: -1px;
  user-select: none;
}

.tab-item:hover {
  color: var(--ts-text-color);
  background: rgba(0, 0, 0, 0.02);
  border-radius: 8px 8px 0 0;
}

/* 激活状态：渐变风格 */
.tab-item.active {
  color: #667eea;
  border-bottom: 2px solid #667eea;
  background: linear-gradient(180deg, rgba(102, 126, 234, 0.05) 0%, rgba(255, 255, 255, 0) 100%);
}

.tab-item-icon {
  margin-right: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* 内容区域 */
.tab-content-wrapper {
  padding: 24px;
  animation: fadeIn 0.4s ease;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(5px); }
  to { opacity: 1; transform: translateY(0); }
}

